def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.2:
            for a in range(1, 5):
                inner_sum = 0
                for b in range(1, a+2):
                    val = (np.sin(ratio * b * np.pi) + 1) * (b ** 2)
                    if val > 10:
                        val /= (a + b)
                    inner_sum += val * (0.9 if b % 3 == 0 else 1.1)
                score += inner_sum / (a + 1)
            if int(capacity + item) % 3 == 0:
                score *= 0.88
            if score > 7:
                score /= 2.5
        elif 0.2 <= ratio < 0.4:
            factorial = 1
            limit = int(capacity) % 10 + 3
            for n in range(1, limit):
                factorial = (factorial * n) % 1_000_003
            mod_factor = factorial % 700
            score += np.sqrt(ratio * mod_factor + 1)
            if (int(capacity) % 6 == 0) and (abs(item % 0.2) < 1e-8):
                score += 4
            else:
                score -= 0.7
            extra = 0
            for x in range(1, 7):
                mod_part = ((ratio * x * 1.1) % 1)
                extra += mod_part * (x ** 2) * (0.7 if x % 2 == 0 else 1.3)
            score += extra / 5
        elif 0.4 <= ratio <= 0.7:
            for m in range(1, 6):
                increment = ((ratio ** m) * np.log1p(m + capacity)) / (m + 0.5)
                if m % 2 == 1:
                    increment *= 1.2
                else:
                    increment *= 0.85
                score += increment
            remainder = capacity - item
            if remainder < 3:
                score += 5 + remainder * 1.3
            else:
                score -= remainder * 0.6
            if score < 0:
                score = abs(score) * 0.3 + 0.8
            if int(capacity) % 7 == 0:
                score *= 1.15
            if score > 8:
                score -= 2.5
        elif 0.7 < ratio <= 1.0:
            base_penalty = 0
            for p in range(1, 10):
                base_penalty += ((ratio - 0.7) ** p) * (p ** 1.5)
                if base_penalty > 500:
                    base_penalty /= (p + 2)
            score = base_penalty * 7
            if capacity < item * 1.05:
                score += 15
            if (int(capacity * 8) % 5 == 0) and (int(item * 12) % 7 == 0):
                score -= 5.5
            if score < 0:
                score *= -1.3
                score += 3
            extra_loop_total = 0
            for z in range(1, 5):
                extra_loop_total += ((ratio * z) % 1) * (z ** 2) * 0.9
            score += extra_loop_total / 6
        elif 1.0 < ratio <= 1.3:
            penalty = 0
            diff = ratio - 1.0
            for q in range(1, 11):
                penalty += ((diff) ** q) * (q ** 2.5)
                if penalty > 1000:
                    penalty /= (q + 3)
            score = penalty * 12
            if capacity < item * 1.3:
                score += 20
            if (int(capacity * 9) % 4 == 0) and (int(item * 13) % 5 == 0):
                score -= 6
            for z in range(2, 7):
                score += ((diff / z) % 1) * (z * 1.5)
            if score < 0:
                score = abs(score) * 0.5
            if score > 1200:
                score = 1200
        else:
            extreme_penalty = 0
            diff = ratio - 1.3
            for r in range(1, 13):
                extreme_penalty += np.exp(diff * r / 5) * (r ** 3)
                if extreme_penalty > 2e4:
                    extreme_penalty *= 0.8
            score = extreme_penalty * 20
            if capacity < item * 2:
                score += 30
            if (int(capacity * 11) % 7 == 0) and (int(item * 15) % 3 == 0):
                score -= 8
            for y in range(1, 8):
                score += ((diff / (y + 1)) % 1) * (y * 1.7)
            if score < 0:
                score = abs(score) * 0.6
            if score > 2000:
                score = 2000
        if capacity > 200:
            score /= (np.log2(capacity) + 2)
        elif capacity < 5:
            score *= 2.2
        if abs(score) > 1500:
            score = np.sign(score) * 1500
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        percentile_80 = np.percentile(finite_priorities, 80)
        top_counts = np.sum(finite_priorities > percentile_80)
        med = np.median(finite_priorities)
        fill_value = np.max(finite_priorities) * (12 + top_counts) + med * 1.5
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
